export const categories = [
  "All",
  "Gaming Mouse",
  "Gaming Keyboard",
  "Graphic Cards",
  "Headphones",
  "Monitors",
  "Controllers",
  "Gaming Chairs",
  "Webcams",
  "Microphones",
  "Cooling Fans",
  "Mousepads",
  "Speakers",
];

const PRODUCTS_PER_PAGE = 12;

const Shop = ({ limit, showFilters = true, title = "Shop" }) => {
  const [activeCategory, setActiveCategory] = useState("All");
  const [currentPage, setCurrentPage] = useState(1);

  const categoryFiltered =
    activeCategory === "All"
      ? allProducts
      : allProducts.filter((p) => p.category === activeCategory);

  const usePagination = !limit;
  const totalPages = usePagination
    ? Math.max(1, Math.ceil(categoryFiltered.length / PRODUCTS_PER_PAGE))
    : 1;

  const pageStart = (currentPage - 1) * PRODUCTS_PER_PAGE;
  const paginated = usePagination
    ? categoryFiltered.slice(pageStart, pageStart + PRODUCTS_PER_PAGE)
    : categoryFiltered;

  const filteredProducts = limit ? categoryFiltered.slice(0, limit) : paginated;

  const handleCategoryClick = (cat) => {
    setActiveCategory(cat);
    setCurrentPage(1);
  };

  const goToPage = (page) => {
    setCurrentPage(page);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  return (
    <div className="shop-page">
      <h1 className="shop-title">{title}</h1>

      {showFilters && (
      <div className="shop-filters">
        {categories.map((cat) => (
          <button
            key={cat}
            className={`shop-filter-btn ${
              activeCategory === cat ? "shop-filter-active" : ""
            }`}
            onClick={() => handleCategoryClick(cat)}
          >
            {cat}
          </button>
        ))}
      </div>
      )}

      <div className="shop-grid">
        {filteredProducts.map((product) => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>

      {usePagination && totalPages > 1 && (
        <div className="shop-pagination">
          <button
            className="shop-page-btn"
            onClick={() => goToPage(currentPage - 1)}
            disabled={currentPage === 1}
          >
            Prev
          </button>

          {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
            <button
              key={page}
              className={`shop-page-btn ${
                currentPage === page ? "shop-page-btn-active" : ""
              }`}
              onClick={() => goToPage(page)}
            >
              {page}
            </button>
          ))}

          <button
            className="shop-page-btn"
            onClick={() => goToPage(currentPage + 1)}
            disabled={currentPage === totalPages}
          >
            Next
          </button>
        </div>
      )}

      {limit && (
        <div className="shop-view-all">
          <Link to="/shop" className="shop-view-all-link">
            View All Products →
          </Link>
        </div>
      )}
    </div>
  );
};

export default Shop;
